package policy

import (
	"context"
	"io"

	"github.com/sirupsen/logrus"

	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

// Verdict represents the outcome of a policy evaluation decision.
type Verdict string

const (
	// VerdictAllow indicates that traffic is allowed by policy.
	VerdictAllow Verdict = "allow"
	// VerdictDeny indicates that traffic is denied by policy.
	VerdictDeny Verdict = "deny"
	// VerdictUndecided indicates that no policy decision has been reached.
	VerdictUndecided Verdict = "undecided"
)

// PolicyAuditLogger provides structured logging of policy evaluation decisions
// for audit and debugging purposes. It is safe for concurrent use.
type PolicyAuditLogger struct {
	mu       lock.Mutex
	logLevel logrus.Level
	logger   *logrus.Entry
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger that integrates with
// Cilium's logging framework and emits structured log entries at the given level.
func NewPolicyAuditLogger(level logrus.Level) *PolicyAuditLogger {
	return &PolicyAuditLogger{
		logLevel: level,
		logger:   logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-audit"),
	}
}

// NewPolicyAuditLoggerWithOutput creates a new PolicyAuditLogger that writes
// JSON-structured audit log entries to the provided writer at the given level.
func NewPolicyAuditLoggerWithOutput(level logrus.Level, out io.Writer) *PolicyAuditLogger {
	auditLogger := logrus.New()
	auditLogger.SetFormatter(&logrus.JSONFormatter{})
	auditLogger.SetLevel(level)
	auditLogger.SetOutput(out)
	return &PolicyAuditLogger{
		logLevel: level,
		logger:   auditLogger.WithField(logfields.LogSubsys, "policy-audit"),
	}
}

// SetLogLevel updates the log level used by the PolicyAuditLogger.
func (l *PolicyAuditLogger) SetLogLevel(level logrus.Level) {
	l.mu.Lock()
	defer l.mu.Unlock()
	l.logLevel = level
}

// LogDecision records a structured audit log entry for a policy verdict.
//
// Parameters:
//   - identity: the security identity string for the traffic source or destination
//   - policy:   a human-readable identifier for the policy being evaluated
//   - verdict:  the policy decision outcome (e.g. VerdictAllow, VerdictDeny)
//   - reason:   a free-form explanation of why the verdict was reached
func (l *PolicyAuditLogger) LogDecision(identity, policy string, verdict Verdict, reason string) {
	l.mu.Lock()
	defer l.mu.Unlock()

	entry := l.logger.WithFields(logrus.Fields{
		logfields.Identity: identity,
		logfields.PolicyID: policy,
		"verdict":          string(verdict),
		"reason":           reason,
	})

	l.emit(entry, "policy decision")
}

// LogEvaluation records a structured audit log entry for a policy map key
// evaluation. The selectorCache parameter may be nil; when non-nil the number
// of cached selectors is included in the log entry.
//
// Parameters:
//   - ctx:           context carrying request-scoped values (reserved for future use)
//   - policyKey:     the policy map key that was evaluated
//   - selectorCache: the SelectorCache used during evaluation, or nil
//   - result:        true if the key matched an allow entry, false otherwise
func (l *PolicyAuditLogger) LogEvaluation(ctx context.Context, policyKey Key, selectorCache *SelectorCache, result bool) {
	l.mu.Lock()
	defer l.mu.Unlock()

	fields := logrus.Fields{
		logfields.PolicyKey: policyKey.String(),
		"result":            result,
	}

	if selectorCache != nil {
		selectorCache.mutex.RLock()
		fields["selectorCount"] = len(selectorCache.selectors)
		selectorCache.mutex.RUnlock()
	}

	entry := l.logger.WithFields(fields)
	l.emit(entry, "policy evaluation")
}

// emit writes the log entry at the configured level. Must be called with l.mu held.
func (l *PolicyAuditLogger) emit(entry *logrus.Entry, msg string) {
	switch l.logLevel {
	case logrus.DebugLevel, logrus.TraceLevel:
		entry.Debug(msg)
	case logrus.WarnLevel:
		entry.Warn(msg)
	case logrus.ErrorLevel:
		entry.Error(msg)
	default:
		entry.Info(msg)
	}
}

