// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package policy

import (
	"bytes"
	"context"
	"encoding/json"
	"strings"
	"sync"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

// TestNewPolicyAuditLogger verifies that a PolicyAuditLogger can be created
// and that its initial state is correct.
func TestNewPolicyAuditLogger(t *testing.T) {
	l := NewPolicyAuditLogger(logrus.InfoLevel)
	require.NotNil(t, l)
	assert.Equal(t, logrus.InfoLevel, l.logLevel)
	assert.NotNil(t, l.logger)
}

// TestNewPolicyAuditLoggerWithOutput verifies that a PolicyAuditLogger backed
// by a custom writer emits JSON-formatted output.
func TestNewPolicyAuditLoggerWithOutput(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLoggerWithOutput(logrus.InfoLevel, &buf)
	require.NotNil(t, l)

	l.LogDecision("identity-1", "test-policy", VerdictAllow, "unit test")

	output := buf.String()
	require.NotEmpty(t, output, "expected log output")

	// Verify the output is valid JSON.
	var entry map[string]interface{}
	err := json.Unmarshal([]byte(strings.TrimSpace(output)), &entry)
	require.NoError(t, err, "log output should be valid JSON")

	assert.Equal(t, "policy-audit", entry[logfields.LogSubsys])
	assert.Equal(t, "policy decision", entry["msg"])
	assert.Equal(t, string(VerdictAllow), entry["verdict"])
}

// TestSetLogLevel verifies that SetLogLevel updates the configured level.
func TestSetLogLevel(t *testing.T) {
	l := NewPolicyAuditLogger(logrus.InfoLevel)
	l.SetLogLevel(logrus.DebugLevel)
	assert.Equal(t, logrus.DebugLevel, l.logLevel)
}

// TestLogDecision verifies that LogDecision emits a log entry containing the
// expected structured fields.
func TestLogDecision(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLoggerWithOutput(logrus.InfoLevel, &buf)

	l.LogDecision("identity-42", "my-policy", VerdictDeny, "no matching rule")

	output := strings.TrimSpace(buf.String())
	require.NotEmpty(t, output)

	var entry map[string]interface{}
	require.NoError(t, json.Unmarshal([]byte(output), &entry))

	assert.Equal(t, "identity-42", entry[logfields.Identity])
	assert.Equal(t, "my-policy", entry[logfields.PolicyID])
	assert.Equal(t, string(VerdictDeny), entry["verdict"])
	assert.Equal(t, "no matching rule", entry["reason"])
	assert.Equal(t, "policy decision", entry["msg"])
}

// TestLogDecisionVerdicts verifies that all Verdict constants are accepted by
// LogDecision without panicking.
func TestLogDecisionVerdicts(t *testing.T) {
	verdicts := []Verdict{VerdictAllow, VerdictDeny, VerdictUndecided}
	for _, v := range verdicts {
		var buf bytes.Buffer
		l := NewPolicyAuditLoggerWithOutput(logrus.InfoLevel, &buf)
		// Must not panic.
		l.LogDecision("id", "pol", v, "reason")
		assert.NotEmpty(t, buf.String(), "expected output for verdict %s", v)
	}
}

// TestLogEvaluationWithoutSelectorCache verifies that LogEvaluation works when
// selectorCache is nil.
func TestLogEvaluationWithoutSelectorCache(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLoggerWithOutput(logrus.InfoLevel, &buf)

	key := Key{
		Identity:         identity.ReservedIdentityHost.Uint32(),
		InvertedPortMask: 0xffff,
	}
	l.LogEvaluation(context.Background(), key, nil, true)

	output := strings.TrimSpace(buf.String())
	require.NotEmpty(t, output)

	var entry map[string]interface{}
	require.NoError(t, json.Unmarshal([]byte(output), &entry))

	assert.Equal(t, "policy evaluation", entry["msg"])
	assert.Equal(t, true, entry["result"])
	assert.NotEmpty(t, entry[logfields.PolicyKey])
	// selectorCount should not be present when selectorCache is nil.
	_, hasSelectorCount := entry["selectorCount"]
	assert.False(t, hasSelectorCount)
}

// TestLogEvaluationWithSelectorCache verifies that LogEvaluation includes the
// selectorCount field when a non-nil SelectorCache is provided.
func TestLogEvaluationWithSelectorCache(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLoggerWithOutput(logrus.InfoLevel, &buf)

	sc := NewSelectorCache(identity.IdentityMap{})

	key := Key{
		Identity:         identity.ReservedIdentityHost.Uint32(),
		InvertedPortMask: 0xffff,
	}
	l.LogEvaluation(context.Background(), key, sc, false)

	output := strings.TrimSpace(buf.String())
	require.NotEmpty(t, output)

	var entry map[string]interface{}
	require.NoError(t, json.Unmarshal([]byte(output), &entry))

	assert.Equal(t, "policy evaluation", entry["msg"])
	assert.Equal(t, false, entry["result"])
	_, hasSelectorCount := entry["selectorCount"]
	assert.True(t, hasSelectorCount, "selectorCount should be present when selectorCache is non-nil")
}

// TestLogDecisionLogLevels verifies that LogDecision respects the configured
// log level and emits output at each supported level.
func TestLogDecisionLogLevels(t *testing.T) {
	levels := []logrus.Level{
		logrus.TraceLevel,
		logrus.DebugLevel,
		logrus.InfoLevel,
		logrus.WarnLevel,
		logrus.ErrorLevel,
	}
	for _, level := range levels {
		var buf bytes.Buffer
		l := NewPolicyAuditLoggerWithOutput(level, &buf)
		l.LogDecision("id", "pol", VerdictAllow, "test")
		assert.NotEmpty(t, buf.String(), "expected output at level %s", level)
	}
}

// TestPolicyAuditLoggerConcurrency verifies that concurrent calls to
// LogDecision and LogEvaluation do not cause data races.
func TestPolicyAuditLoggerConcurrency(t *testing.T) {
	var buf bytes.Buffer
	l := NewPolicyAuditLoggerWithOutput(logrus.InfoLevel, &buf)
	sc := NewSelectorCache(identity.IdentityMap{})
	key := Key{Identity: identity.ReservedIdentityHost.Uint32(), InvertedPortMask: 0xffff}

	const goroutines = 20
	var wg sync.WaitGroup
	wg.Add(goroutines * 2)

	for i := 0; i < goroutines; i++ {
		go func() {
			defer wg.Done()
			l.LogDecision("id", "pol", VerdictAllow, "concurrent")
		}()
		go func() {
			defer wg.Done()
